        avatar.startAvatar();
        stt.startListening();
      }
    };

    socket.on("mira_speech", handleFirstSpeech);
    return () => {
      socket.off("mira_speech", handleFirstSpeech);
      sessionStartedViaFallback.current = false;
    };
